   251→  padding: 0.65rem 1.5rem;
   252→  border: var(--border-width) solid var(--clr-black);
   253→  font-weight: 700;
   254→  box-shadow: 3px 3px 0px var(--clr-black);
   255→  transition: var(--transition);
